(async () => {
  const fs = require('node:fs');
  const path = require('node:path');
  const os = require('node:os');
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'circ-'));
  fs.writeFileSync(path.join(dir, 'a.mjs'), 'import { bFn } from "./b.mjs"; export function aFn() { return "a"; } export function callB() { return bFn(); }');
  fs.writeFileSync(path.join(dir, 'b.mjs'), 'import { aFn } from "./a.mjs"; export function bFn() { return "b+" + aFn(); }');
  const mod = await import('file://' + path.join(dir, 'a.mjs'));
  console.log(mod.callB());
  fs.rmSync(dir, { recursive: true, force: true });
})();

